"use client";

import { useEffect, useMemo, useState } from "react";

type BingoCell = {
  id: number;
  text: string;
  isFree?: boolean;
};

function generateBingoGrid(
  items: string[],
  size: number,
  useFreeCenter: boolean
): BingoCell[][] {
  const totalCells = size * size;
  const sanitized = items
    .map((v) => v.trim())
    .filter((v) => v.length > 0);

  const pool = [...sanitized];
  while (pool.length < totalCells) {
    pool.push(...sanitized);
    if (sanitized.length === 0) break;
  }

  const shuffled = pool
    .slice(0, totalCells)
    .map((text, idx) => ({ text, sort: Math.random(), idx }))
    .sort((a, b) => a.sort - b.sort)
    .map((x) => x.text);

  const grid: BingoCell[][] = [];
  let id = 0;

  for (let row = 0; row < size; row++) {
    const rowCells: BingoCell[] = [];
    for (let col = 0; col < size; col++) {
      const index = row * size + col;
      const isCenter = useFreeCenter && size % 2 === 1 && index === (totalCells - 1) / 2;
      rowCells.push({
        id: id++,
        text: isCenter ? "FREE" : shuffled[index] ?? "",
        isFree: isCenter,
      });
    }
    grid.push(rowCells);
  }

  return grid;
}

export default function HomePage() {
  const [rawItems, setRawItems] = useState(
    [
      "Pizza",
      "Sushi",
      "Burgers",
      "Tacos",
      "Pasta",
      "Salad",
      "Fries",
      "Ice Cream",
      "Donuts",
      "Coffee",
      "Tea",
      "Smoothie",
      "Sandwich",
      "Soup",
      "Steak",
      "Curry",
      "Dumplings",
      "Ramen",
      "BBQ",
      "Chocolate",
      "Cookies",
      "Cake",
      "Juice",
      "Waffles",
      "Pancakes",
    ].join("\n")
  );
  const [size, setSize] = useState(5);
  const [useFreeCenter, setUseFreeCenter] = useState(true);
  const [seed, setSeed] = useState(0);
  const [isClient, setIsClient] = useState(false);
  const [generatedAt, setGeneratedAt] = useState<string | null>(null);

  useEffect(() => {
    setIsClient(true);
    setGeneratedAt(new Date().toLocaleString());
  }, []);

  const items = useMemo(
    () =>
      rawItems
        .split("\n")
        .map((v) => v.trim())
        .filter((v) => v.length > 0),
    [rawItems]
  );

  const grid = useMemo(
    () =>
      isClient ? generateBingoGrid(items, size, useFreeCenter) : ([] as BingoCell[][]),
    [isClient, items, size, useFreeCenter, seed]
  );

  const handleShuffle = () => {
    setSeed((s) => s + 1);
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <main className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-950 to-slate-900">
      <div className="mx-auto flex min-h-screen w-full flex-col gap-8 px-4 pb-10 pt-6 md:px-6 lg:px-10 lg:pt-10">
        <header className="flex flex-col items-start justify-between gap-4 md:flex-row md:items-center">
          <div>
            <div className="inline-flex items-center gap-2 rounded-full border border-emerald-500/40 bg-emerald-500/10 px-3 py-1 text-xs font-medium uppercase tracking-wide text-emerald-300">
              <span className="h-1.5 w-1.5 rounded-full bg-emerald-400" />
              Instant Bingo Card Generator
            </div>
            <h1 className="mt-3 text-3xl font-semibold tracking-tight text-slate-50 sm:text-4xl lg:text-5xl">
              Create custom{" "}
              <span className="bg-gradient-to-r from-emerald-300 via-emerald-400 to-teal-300 bg-clip-text text-transparent">
                bingo cards
              </span>{" "}
              in seconds.
            </h1>
            <p className="mt-3 max-w-xl text-sm text-slate-400 sm:text-base">
              Paste your own list of items, choose the grid size, and instantly
              generate a beautiful, printable bingo card for your next game
              night, classroom, or event.
            </p>
          </div>
          <div className="flex items-center gap-3 self-stretch md:self-auto">
            <button className="btn-ghost w-full md:w-auto" onClick={handlePrint}>
              Print / Save as PDF
            </button>
            <button className="btn-primary w-full md:w-auto" onClick={handleShuffle}>
              Shuffle Card
            </button>
          </div>
        </header>

        <section className="grid gap-6 lg:grid-cols-[minmax(0,1.1fr)_minmax(0,1.2fr)] lg:items-start">
          <div className="card p-5 sm:p-6">
            <div className="flex items-center justify-between gap-2">
              <h2 className="text-sm font-semibold uppercase tracking-wide text-slate-300">
                Card Settings
              </h2>
              <span className="badge">Step 1 · Configure</span>
            </div>

            <div className="mt-4 space-y-4">
              <div className="space-y-2">
                <label className="field-label" htmlFor="items">
                  Bingo items
                </label>
                <p className="text-[11px] text-slate-500">
                  One item per line. We&apos;ll randomly place them on the card. If
                  you provide fewer items than cells, we&apos;ll reuse them.
                </p>
                <textarea
                  id="items"
                  className="textarea min-h-[200px] font-mono text-xs sm:text-sm"
                  value={rawItems}
                  onChange={(e) => setRawItems(e.target.value)}
                />
              </div>

              <div className="grid grid-cols-2 gap-4 sm:grid-cols-3">
                <div className="space-y-1.5">
                  <label className="field-label" htmlFor="size">
                    Grid size
                  </label>
                  <select
                    id="size"
                    className="select"
                    value={size}
                    onChange={(e) => setSize(Number(e.target.value))}
                  >
                    {[3, 4, 5, 6].map((n) => (
                      <option key={n} value={n}>
                        {n} × {n}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="space-y-1.5 col-span-2 sm:col-span-1">
                  <span className="field-label">Center cell</span>
                  <label className="mt-1 flex cursor-pointer items-center gap-2 rounded-xl border border-slate-700/70 bg-slate-900/60 px-3 py-2 text-xs text-slate-200 transition hover:border-emerald-400/70 hover:bg-slate-900">
                    <input
                      type="checkbox"
                      className="h-4 w-4 rounded border-slate-500 bg-slate-900 text-emerald-500"
                      checked={useFreeCenter}
                      onChange={(e) => setUseFreeCenter(e.target.checked)}
                    />
                    <span>Use FREE space in the center</span>
                  </label>
                </div>
              </div>

              <div className="flex flex-wrap items-center justify-between gap-3 pt-2">
                <p className="text-[11px] text-slate-500">
                  Currently using{" "}
                  <span className="font-semibold text-slate-300">
                    {items.length}
                  </span>{" "}
                  unique items for a{" "}
                  <span className="font-semibold text-slate-300">
                    {size} × {size}
                  </span>{" "}
                  card.
                </p>
                <div className="flex items-center gap-2 text-[11px] text-slate-500">
                  <span className="inline-flex h-1.5 w-1.5 rounded-full bg-emerald-400" />
                  Tip: Use your own theme like team building prompts, vocab
                  words, or party dares.
                </div>
              </div>
            </div>
          </div>

          <div className="relative">
            <div className="pointer-events-none absolute -inset-4 -z-10 bg-[radial-gradient(circle_at_top,_rgba(16,185,129,0.2),_transparent_55%)] opacity-80" />
            <div className="card relative flex aspect-square max-h-[560px] flex-col overflow-hidden p-4 sm:p-6 lg:p-8 print:shadow-none">
              <div className="mb-3 flex items-center justify-between gap-2">
                <div className="space-y-0.5">
                  <p className="text-[11px] font-semibold uppercase tracking-[0.22em] text-emerald-300">
                    Bingo
                  </p>
                  <p className="text-xs text-slate-400">
                    Auto-generated from your items
                  </p>
                </div>
                <div className="text-right text-[10px] text-slate-500">
                  <p>Size: {size} × {size}</p>
                  {useFreeCenter && <p>Center: FREE</p>}
                </div>
              </div>

              {isClient ? (
                <div
                  className="grid flex-1 gap-[3px] rounded-xl border border-slate-700/70 bg-slate-900/90 p-[3px] sm:gap-1 sm:p-1"
                  style={{ gridTemplateColumns: `repeat(${size}, minmax(0, 1fr))` }}
                >
                  {grid.flat().map((cell) => (
                    <div
                      key={cell.id}
                      className={`bingo-cell ${
                        cell.isFree ? "bingo-cell-free" : ""
                      }`}
                    >
                      <span className="line-clamp-3">{cell.text}</span>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="flex flex-1 items-center justify-center rounded-xl border border-dashed border-slate-700/70 bg-slate-900/60 text-[11px] text-slate-500">
                  Preparing your bingo card…
                </div>
              )}

              <div className="mt-3 flex items-center justify-between text-[10px] text-slate-500">
                <span>{generatedAt ? `Generated at ${generatedAt}` : "\u00A0"}</span>
                <span>Print this page to use your card</span>
              </div>
            </div>
          </div>
        </section>
      </div>
    </main>
  );
}

